const RegexTester = () => {
  const [pattern, setPattern] = React.useState('[A-Za-z]+');
  const [flags, setFlags] = React.useState('g');
  const [text, setText] = React.useState('Hello World! This is a test. Regex is powerful.');
  const [error, setError] = React.useState('');
  const [matches, setMatches] = React.useState([]);

  React.useEffect(() => {
    setError('');
    setMatches([]);
    if (!pattern) return;
    try {
      const re = new RegExp(pattern, flags);
      const found = [];
      let m;
      if (flags.includes('g')) {
        while ((m = re.exec(text)) !== null) {
          if (m.index === re.lastIndex) re.lastIndex++;
          found.push({ text: m[0], index: m.index, groups: m.slice(1) });
        }
      } else {
        m = re.exec(text);
        if (m) found.push({ text: m[0], index: m.index, groups: m.slice(1) });
      }
      setMatches(found);
    } catch (e) {
      setError(e.message);
    }
  }, [pattern, flags, text]);

  const toggleFlag = (f) => {
    setFlags(flags.includes(f) ? flags.replace(f, '') : flags + f);
  };

  const renderHighlighted = () => {
    if (error || !pattern || !matches.length) return text;
    const parts = [];
    let last = 0;
    matches.forEach((m, i) => {
      if (m.index > last) parts.push(React.createElement('span', { key: 't' + i }, text.slice(last, m.index)));
      parts.push(React.createElement('mark', { key: 'm' + i, style: { background: '#fde047', borderRadius: '2px', padding: '0 2px' } }, text.slice(m.index, m.index + m.text.length)));
      last = m.index + m.text.length;
    });
    if (last < text.length) parts.push(React.createElement('span', { key: 'end' }, text.slice(last)));
    return parts;
  };

  return React.createElement('div', { style: { fontFamily: 'system-ui, sans-serif', padding: '16px', display: 'flex', flexDirection: 'column', gap: '14px', height: '100%', overflow: 'auto' } },
    React.createElement('h3', { style: { margin: 0, fontSize: '16px', fontWeight: 600, color: '#111827' } }, 'Regex Tester'),
    React.createElement('div', null,
      React.createElement('div', { style: { fontSize: '11px', fontWeight: 600, color: '#6b7280', marginBottom: '4px' } }, 'Pattern'),
      React.createElement('div', { style: { display: 'flex', gap: '8px' } },
        React.createElement('input', {
          value: pattern,
          onChange: e => setPattern(e.target.value),
          placeholder: 'Enter regex pattern...',
          style: { flex: 1, fontSize: '14px', padding: '8px 10px', borderRadius: '6px', border: '1px solid ' + (error ? '#fca5a5' : '#d1d5db'), fontFamily: 'monospace', outline: 'none' }
        }),
        React.createElement('span', { style: { fontSize: '18px', color: '#6b7280', alignSelf: 'center' } }, '/')
      ),
      error && React.createElement('div', { style: { fontSize: '12px', color: '#dc2626', marginTop: '4px' } }, error)
    ),
    React.createElement('div', null,
      React.createElement('div', { style: { fontSize: '11px', fontWeight: 600, color: '#6b7280', marginBottom: '4px' } }, 'Flags'),
      React.createElement('div', { style: { display: 'flex', gap: '6px' } },
        ['g', 'i', 'm', 's', 'u'].map(f => React.createElement('button', {
          key: f,
          onClick: () => toggleFlag(f),
          style: {
            fontSize: '12px',
            padding: '4px 10px',
            borderRadius: '4px',
            border: '1px solid #d1d5db',
            background: flags.includes(f) ? '#2563eb' : '#fff',
            color: flags.includes(f) ? '#fff' : '#374151',
            cursor: 'pointer',
            fontWeight: 600
          }
        }, f))
      )
    ),
    React.createElement('div', null,
      React.createElement('div', { style: { fontSize: '11px', fontWeight: 600, color: '#6b7280', marginBottom: '4px' } }, 'Test Text'),
      React.createElement('textarea', {
        value: text,
        onChange: e => setText(e.target.value),
        placeholder: 'Enter text to test against...',
        style: { width: '100%', minHeight: '80px', fontSize: '13px', padding: '10px', borderRadius: '6px', border: '1px solid #d1d5db', resize: 'vertical', fontFamily: 'monospace', boxSizing: 'border-box' }
      })
    ),
    React.createElement('div', null,
      React.createElement('div', { style: { fontSize: '11px', fontWeight: 600, color: '#6b7280', marginBottom: '4px' } }, 'Highlighted Matches (', matches.length, ')'),
      React.createElement('div', { style: { background: '#f9fafb', borderRadius: '6px', padding: '10px', border: '1px solid #e5e7eb', fontSize: '13px', fontFamily: 'monospace', lineHeight: 1.6, minHeight: '60px', wordBreak: 'break-word' } }, renderHighlighted())
    ),
    matches.length > 0 && React.createElement('div', { style: { display: 'flex', flexDirection: 'column', gap: '6px' } },
      React.createElement('div', { style: { fontSize: '11px', fontWeight: 600, color: '#6b7280' } }, 'Match Details'),
      matches.slice(0, 10).map((m, i) => React.createElement('div', { key: i, style: { background: '#fff', borderRadius: '4px', padding: '6px 10px', border: '1px solid #e5e7eb', fontSize: '12px', fontFamily: 'monospace' } },
        React.createElement('span', { style: { color: '#2563eb', fontWeight: 700 } }, m.text),
        ' at index ', m.index,
        m.groups.length > 0 && React.createElement('span', { style: { color: '#6b7280' } }, ' | groups: ', m.groups.map((g, j) => React.createElement('span', { key: j, style: { background: '#e0e7ff', padding: '1px 4px', borderRadius: '2px', marginLeft: '4px' } }, g || '(empty)')))
      ))
    )
  );
};
render(<RegexTester/>);
